"use strict";(self.webpackChunk_servicenow_sdk_docs=self.webpackChunk_servicenow_sdk_docs||[]).push([["816605"],{535804(e){e.exports=JSON.parse('{"tag":{"label":"flow-designer","permalink":"/sdk/4.9.0/tags/flow-designer","allTagsPath":"/sdk/4.9.0/tags","count":7,"items":[{"id":"api/flow/flow-api","title":"Flow","description":"Creates a Flow record (syshubflow) that defines a series of actions to execute when triggered.","permalink":"/sdk/4.9.0/api/flow/flow-api"},{"id":"api/flow/wfa-flow-logic-api","title":"Flow Logic","description":"The wfa.flowLogic namespace provides control flow operators for branching, looping, and flow control within Flow and Subflow bodies.","permalink":"/sdk/4.9.0/api/flow/wfa-flow-logic-api"},{"id":"guides/registering-events-guide","title":"Registering Events Guide","description":"Guide for registering custom ServiceNow events in the Event Registry (sysevent_register) using the Record API, including custom queue configuration for high-volume event processing. Use when a custom event name is referenced, when building event-driven applications, or when the user mentions event registry, custom events, gs.eventQueue(), or custom queues.","permalink":"/sdk/4.9.0/guides/registering-events-guide"},{"id":"guides/service-catalog-guide","title":"Service Catalog","description":"Guide for building ServiceNow Service Catalog components using the Fluent API \u2014 catalog items [sccatitem], record producers [sccatitemproducer], variables [itemoptionnew], variable sets [itemoptionnewset], UI policies [cataloguipolicy], and client scripts [catalogscriptclient]. Whenever the requirement is a form that captures user input and creates a record in a table \u2014 e.g., problem, incident, change_request, or a custom table, including mapping mandatory fields, applying validation, and confirming submission \u2014 the correct metadata is a Record Producer (CatalogItemRecordProducer), NOT a UI Page or a Scripted REST API. A Record Producer provides the form, field mapping (mapToField), validation (catalog UI policies + client scripts), and built-in submit/confirm behavior with no custom page or endpoint. Use a catalog item instead when ordering goods/services with approvals and fulfillment. Also use this guide when the user mentions service catalog, catalog items, record producers, variables, variable sets, UI policies, client scripts, form validation, dynamic fields, onChange, onLoad, onSubmit, ordering, or self-service. Includes property references, code examples, field mapping, scripting patterns, and best practices for end-to-end Service Catalog configuration. Only supported in SDK 4.3.0 or higher","permalink":"/sdk/4.9.0/guides/service-catalog-guide"},{"id":"guides/wfa-flow-guide","title":"Workflow Automation Flow Guide","description":"Comprehensive guide for creating and editing ServiceNow Workflow Automation (WFA) flows using the Fluent SDK. Covers Flow Designer flows including triggers, actions, flow logic, data pills, approvals, and service catalog integration. Use this when implementing event-driven automation, scheduled tasks, approval workflows, or any WFA component.","permalink":"/sdk/4.9.0/guides/wfa-flow-guide"},{"id":"guides/wfa-flow-logic-guide","title":"Workflow Automation Flow Logic Guide","description":"Flow logic constructs control how a flow executes -- branching, looping, and termination. They are invoked from inside a flow or subflow body via wfa.flowLogic.*.","permalink":"/sdk/4.9.0/guides/wfa-flow-logic-guide"},{"id":"guides/wfa-trigger-guide","title":"Workflow Automation Trigger Guide","description":"Triggers define when a Workflow Automation flow activates. They are the first argument to wfa.trigger() and fall into three categories:","permalink":"/sdk/4.9.0/guides/wfa-trigger-guide"}],"unlisted":false}}')}}]);